  `order_reference` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `customer_name` varchar(190) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `customer_email` varchar(190) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `customer_company` varchar(190) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `vat_number` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `currency_iso` varchar(8) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `total_tax_excl` decimal(14,6) NOT NULL DEFAULT '0.000000',
  `total_tax_incl` decimal(14,6) NOT NULL DEFAULT '0.000000',
  `status` enum('received','ready','sent','accepted','rejected','archived') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'received',
  `channel` enum('prestashop','manual','pdp','chorus') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'prestashop',
  `e_invoice_format` enum('pdf','facturx','ubl','cii','unknown') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pdf',
  `pdf_url` text COLLATE utf8mb4_unicode_ci,
