  `pdf_hash` char(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pdf_downloaded_at` datetime DEFAULT NULL,
  `xml_payload` longtext COLLATE utf8mb4_unicode_ci,
  `facturx_file_path` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `facturx_profile` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `facturx_generated_at` datetime DEFAULT NULL,
  `raw_json` longtext COLLATE utf8mb4_unicode_ci,
  `source_hash` char(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `synced_at` datetime NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_invocean_prestashop_invoice` (`prestashop_invoice_id`),
  KEY `idx_invocean_invoice_date` (`invoice_date`),
  KEY `idx_invocean_status` (`status`),
  KEY `idx_invocean_order` (`order_id`),
  KEY `idx_invocean_customer_email` (`customer_email`)
